def generate_invoice_pdf(invoice_data):
    """Generate a PDF invoice from invoice data and return it as a BytesIO buffer."""
    buffer = io.BytesIO()
    
    doc = SimpleDocTemplate(
        buffer,
        pagesize=letter,
        rightMargin=0.75 * inch,
        leftMargin=0.75 * inch,
        topMargin=0.75 * inch,
        bottomMargin=0.75 * inch,
    )
    
    styles = getSampleStyleSheet()
    elements = []
    
    # Custom styles
    title_style = ParagraphStyle(
        'InvoiceTitle',
        parent=styles['Heading1'],
        fontSize=28,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=6,
    )
    
    heading_style = ParagraphStyle(
        'InvoiceHeading',
        parent=styles['Heading2'],
        fontSize=12,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=4,
    )
    
    normal_style = ParagraphStyle(
        'InvoiceNormal',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#333333'),
    )
    
    small_style = ParagraphStyle(
        'InvoiceSmall',
        parent=styles['Normal'],
        fontSize=9,
        textColor=colors.HexColor('#666666'),
    )
    
    # Header section
    elements.append(Paragraph("INVOICE", title_style))
    elements.append(Spacer(1, 4))
    
    # Invoice metadata table
    invoice_info = [
        [
            Paragraph(f"<b>{invoice_data['company_name']}</b>", normal_style),
            Paragraph(f"<b>Invoice #:</b> {invoice_data['invoice_number']}", normal_style),
        ],
        [
            Paragraph(invoice_data['company_address'], small_style),
            Paragraph(f"<b>Date:</b> {invoice_data['date']}", normal_style),
        ],
        [
            Paragraph("", normal_style),
            Paragraph(f"<b>Due Date:</b> {invoice_data['due_date']}", normal_style),
        ],
        [
            Paragraph("", normal_style),
            Paragraph(f"<b>Status:</b> {invoice_data['status'].upper()}", normal_style),
        ],
    ]
    
    info_table = Table(invoice_info, colWidths=[3.5 * inch, 3.5 * inch])
    info_table.setStyle(TableStyle([
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('ALIGN', (1, 0), (1, -1), 'RIGHT'),
    ]))
    elements.append(info_table)
    elements.append(Spacer(1, 20))
    
    # Bill To section
    elements.append(Paragraph("<b>Bill To:</b>", heading_style))
    elements.append(Paragraph(invoice_data['customer_name'], normal_style))
    elements.append(Paragraph(invoice_data['customer_email'], small_style))
    elements.append(Paragraph(invoice_data['customer_address'], small_style))
    elements.append(Spacer(1, 20))
    
    # Items table
    table_header = [
        Paragraph("<b>Description</b>", normal_style),
        Paragraph("<b>Qty</b>", normal_style),
        Paragraph("<b>Unit Price</b>", normal_style),
        Paragraph("<b>Amount</b>", normal_style),
    ]
    
    table_data = [table_header]
    subtotal = 0.0
    
    for item in invoice_data['items']:
        amount = item['quantity'] * item['unit_price']
        subtotal += amount
        table_data.append([
            Paragraph(item['description'], normal_style),
            Paragraph(str(item['quantity']), normal_style),
            Paragraph(f"${item['unit_price']:,.2f}", normal_style),
            Paragraph(f"${amount:,.2f}", normal_style),
        ])
    
    tax_amount = subtotal * invoice_data['tax_rate']
    total = subtotal + tax_amount
    
    # Add subtotal, tax, and total rows
    table_data.append([
        "", "", Paragraph("<b>Subtotal:</b>", normal_style),
        Paragraph(f"${subtotal:,.2f}", normal_style),
    ])
    table_data.append([
        "", "", Paragraph(f"<b>Tax ({invoice_data['tax_rate'] * 100:.1f}%):</b>", normal_style),
        Paragraph(f"${tax_amount:,.2f}", normal_style),
    ])
    table_data.append([
        "", "", Paragraph("<b>TOTAL:</b>", ParagraphStyle(
            'TotalStyle', parent=normal_style, fontSize=12, textColor=colors.HexColor('#2c3e50')
        )),
        Paragraph(f"<b>${total:,.2f}</b>", ParagraphStyle(
            'TotalAmountStyle', parent=normal_style, fontSize=12, textColor=colors.HexColor('#2c3e50')
        )),
    ])
    
    items_table = Table(
        table_data,
        colWidths=[3.0 * inch, 1.0 * inch, 1.5 * inch, 1.5 * inch],
    )
    
    num_items = len(invoice_data['items'])
    
    items_table.setStyle(TableStyle([
        # Header row
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#2c3e50')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
        ('FONTSIZE', (0, 0), (-1, 0), 10),
        ('BOTTOMPADDING', (0, 0), (-1, 0), 10),
        ('TOPPADDING', (0, 0), (-1, 0), 10),
        
        # Item rows
        ('BACKGROUND', (0, 1), (-1, num_items), colors.HexColor('#f8f9fa')),
        ('ROWBACKGROUNDS', (0, 1), (-1, num_items), [colors.HexColor('#f8f9fa'), colors.white]),
        
        # Grid
        ('GRID', (0, 0), (-1, num_items), 0.5, colors.HexColor('#dee2e6')),
        
        # Alignment
        ('ALIGN', (1, 0), (1, -1), 'CENTER'),
        ('ALIGN', (2, 0), (-1, -1), 'RIGHT'),
        ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
        
        # Padding
        ('TOPPADDING', (0, 1), (-1, -1), 8),
        ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
        ('LEFTPADDING', (0, 0), (-1, -1), 10),
        ('RIGHTPADDING', (0, 0), (-1, -1), 10),
        
        # Total row styling
        ('LINEABOVE', (2, num_items + 1), (-1, num_items + 1), 1, colors.HexColor('#dee2e6')),
        ('LINEABOVE', (2, num_items + 3), (-1, num_items + 3), 2, colors.HexColor('#2c3e50')),
        ('BACKGROUND', (2, num_items + 3), (-1, num_items + 3), colors.HexColor('#ecf0f1')),
    ]))
    
    elements.append(items_table)
    elements.append(Spacer(1, 30))
    
    # Notes section
    if invoice_data.get('notes'):
        elements.append(Paragraph("<b>Notes:</b>", heading_style))
        elements.append(Paragraph(invoice_data['notes'], small_style))
    
    doc.build(elements)
    buffer.seek(0)
    return buffer


