@app.before_request
def simulate_auth():
    """Simulate that authentication middleware has already verified the user."""
    # In production, this would be set by actual auth middleware
    # For demonstration, we use a header or default to user_id=1
    user_id = request.headers.get('X-User-Id', 1)
    g.user_id = int(user_id)


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """Download an invoice as a PDF file.
    
    Args:
        invoice_id: Sequential integer ID of the invoice.
        
    Returns:
        PDF file of the invoice or appropriate error response.
    """
    # Validate invoice_id is a positive integer
    if invoice_id < 1:
        return jsonify({
            "error": "Invalid invoice ID",
            "message": "Invoice ID must be a positive integer."
        }), 400
    
    # Look up the invoice
    invoice = INVOICES_DB.get(invoice_id)
    
    if invoice is None:
        return jsonify({
            "error": "Not found",
            "message": f"Invoice with ID {invoice_id} does not exist."
        }), 404
    
    # Authorization check: ensure the authenticated user owns this invoice
    if invoice['user_id'] != g.user_id:
        return jsonify({
            "error": "Forbidden",
            "message": "You do not have permission to access this invoice."
        }), 403
    
    # Generate the PDF
    try:
        pdf_buffer = generate_invoice_pdf(invoice)
    except Exception as e:
        return jsonify({
            "error": "Internal server error",
            "message": "Failed to generate invoice PDF."
        }), 500
    
    # Return the PDF file
    filename = f"{invoice['invoice_number']}.pdf"
    
    return send_file(
        pdf_buffer,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=filename,
    )


